"use strict";$(".dd-button.email").on("click",function(){$(".dd-menu.email").toggleClass("d-none")});var paymentDate=$("#payment_date").val();$("#payment_date").daterangepicker(selectFromTo(0<paymentDate.length?paymentDate:null));function sendMail(a){return new Promise((b,c)=>{let d="customer"===a?1:3,e={order_id:orderId,action_val:d,type:"orderAction"};$.ajax({type:"POST",url:orderUrl,data:{_token:token,data:e},success:function(a){if(1===a.status)triggerNotification(a.message),b(a);else if("undefined"!=typeof a.error)triggerNotification(a.error),c(a.error);else{let a=jsLang("Something went wrong, please try again.");triggerNotification(a),c(a)}},error:function(a){triggerNotification(a.responseJSON.message),c(a)}})})}function handleMailButtonClick(a,b,c){a.hasClass("disabled")||(a.addClass("disabled").text(jsLang("Mail is sending")+"..."),sendMail(b).finally(()=>{a.removeClass("disabled").text(c)}))}$("#send_mail_to_customer").on("click",function(){handleMailButtonClick($(this),"customer",jsLang("Send Mail to Customer"))}),$("#send_mail_to_vendor").on("click",function(){handleMailButtonClick($(this),"vendor",jsLang("Send Mail to Vendor"))});
